const input = $input.first().json;
const webhookData = $('Webhook').first().json.body;
const prompt = webhookData.prompt;
const filePaths = webhookData.filePaths || [];
const jobId = webhookData.jobId;
const secrets = webhookData._secrets || {};
const promptMeta = webhookData.promptMeta || {};

let systemPrompt = promptMeta.systemPrompt;
if (!systemPrompt || typeof systemPrompt !== 'string' || !systemPrompt.trim()) {
  systemPrompt = 'You are an expert presentation designer. You create visually stunning HTML/CSS slides rendered at 1920×1080 px.

OUTPUT FORMAT — return ONLY valid JSON (no markdown, no code fences):
{
  "theme": {
    "css": ":root { --primary: #2563eb; --font-heading: 'Inter', sans-serif; }",
    "fonts": ["Inter"]
  },
  "slides": [
    {
      "html": "<div class='centered'><h1 class='heading-xl'>Title</h1></div>",
      "css": "",
      "notes": "Speaker notes (optional)"
    }
  ]
}

REFINEMENT MODE:
- Sometimes you will receive an existing slide_data JSON and a user request to update it.
- In refinement mode, you MUST return the COMPLETE updated slide_data JSON (all slides, full theme), not a diff.

CSS FRAMEWORK — each slide is a <div class="slide"> (1920×1080, padding 80px). You have these utilities:

Variables (override in theme.css): --primary, --primary-light, --primary-dark, --bg, --bg-alt, --text, --text-light, --text-muted, --accent, --success, --danger, --font-heading, --font-body, --font-mono.

Layouts: .centered (flex center), .top-title (title + flex body), .split-2 / .split-3 (grid columns), .split-left-wide / .split-right-wide (2:1 / 1:2 grid).

Typography: .heading-xl (72px bold), .heading-lg (52px), .heading-md (40px), .heading-sm (32px), .subtitle (32px light), .body-text (28px), .body-lg (32px), .caption (20px), .small (18px), .bold, .semibold, .uppercase.

Components: .card (bg-alt rounded box), .card-bordered, .card-primary (primary bg white text), .accent-line (80px colored bar), .divider, .tag (primary pill), .tag-outline, .icon-circle / .icon-circle-lg (round icon container), .number-big (96px stat), .quote (left-bordered italic), .code-block (dark mono block).

Lists: .bullets (styled ul), .bullets-lg, .numbered (auto-numbered circles).

Tables: .table (styled with colored header, striped rows).

Charts: .bar-container + .bar (horizontal bars), .stat-value (64px number) + .stat-label.

Backgrounds: .bg-primary, .bg-dark, .bg-gradient, .bg-gradient-light, .bg-alt. Dark backgrounds auto-adjust text and bullet colors.

Spacing: .mt-1..mt-4 (16–64px), .mb-1..mb-3, .gap-1..gap-4, .p-1..p-3, .w-full, .h-full.

Images: .img-contain, .img-cover, .img-rounded.

DESIGN RULES:
- Slide HTML goes INSIDE the .slide container (wrapper added automatically)
- Use framework classes + custom inline styles or per-slide CSS for unique effects
- Use Google Fonts via theme.fonts array (loaded automatically)
- Prefer gradients, shadows, icons (Unicode emoji or SVG), visual hierarchy
- Do NOT use JavaScript
- Do NOT set width/height on the slide itself
- First slide should be a title/cover slide
- Use 5–10 slides for a typical presentation
- If images are provided, reference them in HTML with src="attachment:ATTACHMENT_ID" (we will replace it with a real data URL).
- Use .img-contain for logos/icons, .img-cover for full-slide backgrounds, .img-rounded for rounded corners.
- Respond in the same language as the user's prompt
- Make content professional, concise, and visually polished';
}

const slideCount = Number(promptMeta.slideCount) || 0;
const slidePrompts = Array.isArray(promptMeta.slidePrompts) ? promptMeta.slidePrompts : [];
const presentationSettings = promptMeta.presentationSettings || {};
const fileAttachments = Array.isArray(promptMeta.fileAttachments) ? promptMeta.fileAttachments : [];

let userMessage = '';

if (promptMeta.refinementMode) {
  userMessage += 'REFINEMENT MODE: You are updating an existing presentation.
';
  userMessage += 'Return the COMPLETE updated slide_data JSON with all slides.

';
  userMessage += 'Current slide_data:
' + JSON.stringify(promptMeta.previousSlideData || {}, null, 2) + '

';
  userMessage += 'User request:
' + String(promptMeta.userMessage || '').trim();
} else {
  userMessage = prompt;

  if (slideCount > 0) {
    userMessage += `

Desired slide count: ${slideCount}`;
  }

  if (slidePrompts.length > 0) {
    userMessage += '

Slide-specific prompts:';
    for (const sp of slidePrompts) {
      userMessage += `
- Slide ${sp.slideIndex + 1}: ${sp.prompt}`;
    }
  }

  if (Object.keys(presentationSettings).length > 0) {
    userMessage += '

Presentation theme settings (apply as CSS variable overrides in theme.css):
';
    userMessage += JSON.stringify(presentationSettings, null, 2);
  }

  if (fileAttachments.length > 0) {
    userMessage += '

Uploaded files:';
    for (const f of fileAttachments) {
      const kind = f.base64 ? 'IMAGE' : 'DOCUMENT';
      const pr = f.prompt ? ` — "${String(f.prompt).slice(0, 400)}"` : '';
      const ref = f.base64 && f.attachmentId ? ` (use in HTML as src="attachment:${f.attachmentId}")` : '';
      userMessage += `
- ${f.name} [${kind}]${pr}${ref}`;
    }
  } else if (filePaths.length > 0) {
    userMessage += '

Available files:
' + filePaths.map(f => '- ' + f).join('
');
  }
}

const userContent = [{ type: 'text', text: userMessage }];
for (const f of fileAttachments) {
  if (f && f.base64 && f.mimeType) {
    userContent.push({ type: 'image_url', image_url: { url: `data:${f.mimeType};base64,${f.base64}` } });
  }
}

return [{ json: { systemPrompt, userMessage, userContent, jobId, secrets, promptMeta, filePaths } }];

const input = $input.first().json;
const build = $('Build LLM Prompt').first().json;
const jobId = build.jobId;
const secrets = build.secrets;
const promptMeta = build.promptMeta || {};
const fileAttachments = Array.isArray(promptMeta.fileAttachments) ? promptMeta.fileAttachments : [];

let content = '';
try {
  content = input.choices[0].message.content;
} catch(e) {
  content = JSON.stringify(input);
}

if (content.includes('```')) {
  content = content.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
}

let slideData;
try {
  slideData = JSON.parse(content);
  if (!slideData.slides || !Array.isArray(slideData.slides)) {
    throw new Error('Missing slides array');
  }
  for (let i = 0; i < slideData.slides.length; i++) {
    if (!slideData.slides[i].html || typeof slideData.slides[i].html !== 'string') {
      throw new Error(`Slide ${i} missing html field`);
    }
  }
} catch (e) {
  slideData = {
    theme: { css: ':root { --primary: #dc2626; }' },
    slides: [{
      html: '<div class="centered"><h1 class="heading-xl">Error</h1><p class="subtitle">' + (e.message || 'Failed to parse LLM response').replace(/</g, '&lt;') + '</p></div>',
      css: '',
      notes: ''
    }]
  };
}

// Replace attachment:<id> placeholders with data URLs
if (fileAttachments.length > 0 && slideData && Array.isArray(slideData.slides)) {
  const map = new Map();
  for (const f of fileAttachments) {
    if (f && f.attachmentId && f.base64 && f.mimeType) {
      map.set(String(f.attachmentId), `data:${f.mimeType};base64,${f.base64}`);
    }
  }

  for (const s of slideData.slides) {
    if (!s || typeof s.html !== 'string') continue;
    s.html = s.html.replace(/attachment:\/?\/?([0-9a-fA-F-]{36})/g, (_m, id) => {
      const v = map.get(String(id));
      return v || _m;
    });
  }
}

return [{ json: { slideData, jobId, secrets } }];

const errorData = $input.first().json;
let errorMessage = 'Unknown error occurred in pipeline';
let jobId = null;
let internalApiKey = null;

try {
  if (errorData.execution && errorData.execution.error) {
    errorMessage = errorData.execution.error.message || errorMessage;
  }
} catch (e) {}

try {
  const runData = errorData.execution.data.resultData.runData;
  if (runData['Webhook']) {
    const webhookOutput = runData['Webhook'][0].data.main[0][0].json.body;
    jobId = webhookOutput.jobId;
    internalApiKey = webhookOutput._secrets ? webhookOutput._secrets.internalApiKey : null;
  }
} catch (e) {}

if (!jobId) {
  try {
    const runData = errorData.execution.data.resultData.runData;
    if (runData['Build LLM Prompt']) {
      const bld = runData['Build LLM Prompt'][0].data.main[0][0].json;
      jobId = bld.jobId;
      internalApiKey = bld.secrets ? bld.secrets.internalApiKey : null;
    }
  } catch (e) {}
}

return [{ json: { jobId, errorMessage, internalApiKey } }];
